import React from "react";

export default function WeatherOverlay({ condition, isDaytime }) {
  const getOverlayFile = () => {
    const cond = condition?.toLowerCase() || "";

    if (cond.includes("thunder")) return "thunderstorm.gif";
    if (cond.includes("snow")) return "snow.gif";
    if (cond.includes("rain")) return isDaytime ? "rain.gif" : "rainNight.gif";
    if (cond.includes("cloud") && cond.includes("heavy")) return "cloudy.gif";
    if (cond.includes("cloud")) {
      if (!isDaytime) return "PCnight.gif";
      return "PCday.gif";
    }
    if (cond.includes("wind")) return "Windy-Weather-App.gif";
    if (cond.includes("clear") || cond.includes("sun")) {
      return isDaytime ? "noon.gif" : "night.gif";
    }

    // Default fallback
    return isDaytime ? "sunset.gif" : "night.gif";
  };

  const gif = getOverlayFile();

  return (
    <div
      className="absolute top-0 left-0 w-full h-full z-0 pointer-events-none overflow-hidden"
    >
      <img
        src={`/overlays/${gif}`}
        alt="weather overlay"
        className="w-full h-full object-cover opacity-70"
      />
    </div>
  );
}
